import { BrowserWindow, type WebContents } from "electron";

// WhatsApp Windows VoIP ringtone (assets/sounds/whatsapp_windows_ringtone_02.m4a,
// AAC). In native-bridge web mode the bundle's WebRTC stack stays silent on inbound
// offers (the engine is stubbed — see voip.ts), so nothing rings. We loop this tone
// ourselves while a call is offering, mirroring the Windows client's ringtone.
//
// Same injection pattern as sound.ts: the main process has no <audio>, so the tone
// is decoded to a blob: URL inside the WA page and looped via a persistent element.
// INSTALL_JS self-guards and is injected once per page load.
const INSTALL_JS = "(() => {if (window.__waRing) return;var b64 = \"\";var bin = atob(b64), u8 = new Uint8Array(bin.length);for (var i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);var url = URL.createObjectURL(new Blob([u8], { type: \"audio/mp4\" }));var a = null;window.__waRing = function () { try { if (!a) { a = new Audio(url); a.loop = true; } a.currentTime = 0; a.play().catch(function () {}); } catch (e) {} };window.__waStopRing = function () { try { if (a) { a.pause(); a.currentTime = 0; } } catch (e) {} };})();";

const liveWc = (): WebContents | null => {
  const w = BrowserWindow.getAllWindows().find((b) => !b.isDestroyed());
  return w ? w.webContents : null;
};

export const installRingtone = (wc: WebContents): void => {
  wc.executeJavaScript(INSTALL_JS).catch(() => undefined);
};

const run = (js: string) => liveWc()?.executeJavaScript(js).catch(() => undefined);

export const startRingtone = (): void => { run("window.__waRing && window.__waRing()"); };
export const stopRingtone = (): void => { run("window.__waStopRing && window.__waStopRing()"); };
